import os
import json
import time
import shutil

class DiskCache:
    def __init__(self, cache_dir, default_expiration_seconds=3600):
        self.cache_dir = cache_dir
        self.default_expiration_seconds = default_expiration_seconds
        os.makedirs(self.cache_dir, exist_ok=True)

    def _get_cache_filepath(self, key):
        # Simple key hashing to create a filename
        return os.path.join(self.cache_dir, f"{hash(key)}.json")

    def _is_expired(self, timestamp, expiration_seconds):
        return (time.time() - timestamp) > expiration_seconds

    def get(self, key):
        filepath = self._get_cache_filepath(key)
        if not os.path.exists(filepath):
            return None

        try:
            with open(filepath, 'r') as f:
                cached_data = json.load(f)

            timestamp = cached_data.get('__timestamp__')
            expiration_seconds = cached_data.get('__expiration_seconds__', self.default_expiration_seconds)
            data = cached_data.get('data')

            if timestamp is None or data is None:
                # Malformed cache entry, treat as expired
                self.delete(key)
                return None

            if self._is_expired(timestamp, expiration_seconds):
                self.delete(key)
                return None

            return data
        except (json.JSONDecodeError, IOError, KeyError):
            # Handle corrupted or unreadable files
            self.delete(key)
            return None

    def set(self, key, data, expiration_seconds=None):
        filepath = self._get_cache_filepath(key)
        if expiration_seconds is None:
            expiration_seconds = self.default_expiration_seconds

        cache_entry = {
            '__timestamp__': time.time(),
            '__expiration_seconds__': expiration_seconds,
            'data': data
        }

        try:
            with open(filepath, 'w') as f:
                json.dump(cache_entry, f)
            return True
        except IOError:
            return False

    def delete(self, key):
        filepath = self._get_cache_filepath(key)
        if os.path.exists(filepath):
            try:
                os.remove(filepath)
                return True
            except IOError:
                return False
        return False

    def clear(self):
        """Clears all items from the cache."""
        try:
            shutil.rmtree(self.cache_dir)
            os.makedirs(self.cache_dir, exist_ok=True)
            return True
        except IOError:
            return False

    def __len__(self):
        """Returns the number of items currently in the cache."""
        return len([name for name in os.listdir(self.cache_dir) if os.path.isfile(os.path.join(self.cache_dir, name))])

    def __contains__(self, key):
        """Checks if a key exists in the cache (without checking expiration)."""
        return os.path.exists(self._get_cache_filepath(key))

